import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Plus, Trash2, Monitor, RotateCcw, ZoomIn, ZoomOut, MousePointer2 } from 'lucide-react';

/**
 * --- UTILITIES & CONSTANTS ---
 * In a multi-file app, this might go in 'utils.js' or 'constants.js'
 */
const ASPECT_RATIOS = [
  { label: '16:9 (Standard)', w: 16, h: 9 },
  { label: '21:9 (Ultrawide)', w: 21, h: 9 },
  { label: '32:9 (Super Ultrawide)', w: 32, h: 9 },
  { label: '16:10 (Productivity)', w: 16, h: 10 },
  { label: '4:3 (Retro/iPad)', w: 4, h: 3 },
  { label: '1:1 (Square)', w: 1, h: 1 },
];

const COLORS = [
  'bg-blue-500', 'bg-emerald-500', 'bg-violet-500', 'bg-rose-500', 
  'bg-amber-500', 'bg-cyan-500', 'bg-fuchsia-500', 'bg-indigo-500'
];

const PPI_SCALE = 15; 

const calculateDimensions = (diagonal, ratioW, ratioH) => {
  const angle = Math.atan(ratioH / ratioW);
  const width = diagonal * Math.cos(angle);
  const height = diagonal * Math.sin(angle);
  return { width, height };
};

const formatDim = (inches) => {
  const cm = inches * 2.54;
  return `${Math.round(cm * 10) / 10} cm (${Math.round(inches * 10) / 10}")`;
};

/**
 * --- COMPONENT: MONITOR ITEM ---
 * Represents a single monitor on the canvas.
 */
const MonitorItem = ({ monitor, zoom, isDragging, onMouseDown }) => {
  const { width, height } = calculateDimensions(monitor.diagonal, monitor.ratio.w, monitor.ratio.h);

  // Swap dimensions if portrait
  const widthIn = monitor.orientation === 'landscape' ? width : height;
  const heightIn = monitor.orientation === 'landscape' ? height : width;

  const widthPx = widthIn * PPI_SCALE;
  const heightPx = heightIn * PPI_SCALE;

  return (
    <div
      onMouseDown={(e) => { e.stopPropagation(); onMouseDown(e, monitor.id); }}
      className="absolute group"
      style={{
        transform: `translate(${monitor.x}px, ${monitor.y}px)`,
        width: widthPx,
        height: heightPx,
        cursor: 'move',
        zIndex: isDragging ? 50 : 10
      }}
    >
      {/* Monitor Bezel & Screen */}
      <div 
        className={`w-full h-full bg-slate-800 rounded-sm border-2 border-slate-600 shadow-2xl flex flex-col items-center justify-center relative overflow-hidden transition-shadow ${isDragging ? 'shadow-blue-500/20 ring-2 ring-blue-500' : ''}`}
      >
        {/* Screen Content */}
        <div className={`w-[calc(100%-8px)] h-[calc(100%-8px)] ${monitor.color} opacity-20 absolute inset-0 m-auto`}></div>
        <div className={`w-[calc(100%-8px)] h-[calc(100%-8px)] absolute inset-0 m-auto flex flex-col items-center justify-center p-2 text-center pointer-events-none`}>
          <span className="text-3xl font-bold text-white/90 drop-shadow-md leading-none">{monitor.diagonal}"</span>
          <span className="text-xs text-white/80 drop-shadow-md font-mono mt-1">{monitor.ratio.label}</span>
        </div>

        {/* Hover Overlay */}
        <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center text-xs text-white pointer-events-none p-2 text-center">
          <div className="grid grid-cols-2 gap-x-4 gap-y-1 text-left">
            <span className="text-slate-400">Width:</span> <span>{formatDim(widthIn)}</span>
            <span className="text-slate-400">Height:</span> <span>{formatDim(heightIn)}</span>
            <span className="text-slate-400">Area:</span> <span>{Math.round(widthIn * heightIn)} sq in</span>
          </div>
        </div>
      </div>

      {/* External Dimensions (Engineering lines) */}
      <div className="absolute -top-6 left-0 w-full text-center text-[10px] text-slate-400 font-mono opacity-50 group-hover:opacity-100">
        {formatDim(widthIn)}
      </div>
      <div className="absolute top-0 -left-6 h-full flex items-center text-[10px] text-slate-400 font-mono opacity-50 group-hover:opacity-100 [writing-mode:vertical-lr] rotate-180">
        {formatDim(heightIn)}
      </div>
    </div>
  );
};

/**
 * --- COMPONENT: SIDEBAR ---
 * Handles adding new monitors and listing current ones.
 */
const Sidebar = ({ monitors, onAdd, onRemove, onRotate, stats }) => {
  const [newDiag, setNewDiag] = useState(27);
  const [ratioIdx, setRatioIdx] = useState(0);
  const [customRatio, setCustomRatio] = useState({ w: 16, h: 9 });

  const handleAddClick = () => {
    let finalRatio;
    if (ratioIdx === -1) {
      finalRatio = {
        w: parseFloat(customRatio.w) || 16,
        h: parseFloat(customRatio.h) || 9,
        label: `${customRatio.w}:${customRatio.h}`
      };
    } else {
      finalRatio = ASPECT_RATIOS[ratioIdx];
    }
    onAdd(newDiag, finalRatio);
  };

  return (
    <div className="w-80 flex-shrink-0 bg-slate-800 border-r border-slate-700 flex flex-col shadow-xl z-20">
      <div className="p-4 border-b border-slate-700">
        <h1 className="text-xl font-bold flex items-center gap-2 text-blue-400">
          <Monitor size={24} />
          MultiView Planner
        </h1>
        <p className="text-xs text-slate-400 mt-1">Compare screen sizes & plan layouts.</p>
      </div>

      <div className="p-4 space-y-4 overflow-y-auto flex-1">
        {/* ADD FORM */}
        <div className="bg-slate-700/50 p-4 rounded-lg space-y-3 border border-slate-600">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-300">Add Display</h2>

          <div>
            <label className="block text-xs text-slate-400 mb-1">Diagonal Size (inches)</label>
            <div className="flex items-center gap-2">
              <input 
                type="number" 
                value={newDiag} 
                onChange={(e) => setNewDiag(e.target.value)}
                className="w-full bg-slate-900 border border-slate-600 rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                min="5" max="100"
              />
              <span className="text-sm text-slate-400">"</span>
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-400 mb-1">Aspect Ratio</label>
            <select 
              value={ratioIdx}
              onChange={(e) => setRatioIdx(parseInt(e.target.value))}
              className="w-full bg-slate-900 border border-slate-600 rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
            >
              {ASPECT_RATIOS.map((r, idx) => (
                <option key={idx} value={idx}>{r.label}</option>
              ))}
              <option value={-1}>Custom...</option>
            </select>
          </div>

          {ratioIdx === -1 && (
            <div className="grid grid-cols-2 gap-2 animate-in fade-in slide-in-from-top-2 duration-200">
              <div>
                <label className="block text-xs text-slate-400 mb-1">Width Ratio</label>
                <input 
                  type="number"
                  value={customRatio.w}
                  onChange={(e) => setCustomRatio(p => ({ ...p, w: e.target.value }))}
                  className="w-full bg-slate-900 border border-slate-600 rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="16"
                />
              </div>
              <div>
                <label className="block text-xs text-slate-400 mb-1">Height Ratio</label>
                <input 
                  type="number"
                  value={customRatio.h}
                  onChange={(e) => setCustomRatio(p => ({ ...p, h: e.target.value }))}
                  className="w-full bg-slate-900 border border-slate-600 rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="9"
                />
              </div>
            </div>
          )}

          <button 
            onClick={handleAddClick}
            className="w-full bg-blue-600 hover:bg-blue-500 text-white py-2 rounded-md flex items-center justify-center gap-2 text-sm font-medium transition-colors"
          >
            <Plus size={16} /> Add Display
          </button>
        </div>

        {/* LIST */}
        <div className="space-y-2">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-300">Current Setup</h2>
          {monitors.length === 0 && <p className="text-sm text-slate-500 italic">No displays added.</p>}

          <div className="space-y-2 max-h-[300px] overflow-y-auto pr-1">
            {monitors.map((m) => (
              <div key={m.id} className="bg-slate-700 p-3 rounded flex items-center justify-between group border border-transparent hover:border-slate-500">
                <div className="flex items-center gap-3">
                  <div className={`w-3 h-3 rounded-full ${m.color}`}></div>
                  <div>
                    <div className="text-sm font-medium">{m.diagonal}" {m.ratio.label}</div>
                    <div className="text-xs text-slate-400 capitalize">{m.orientation}</div>
                  </div>
                </div>
                <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => onRotate(m.id)} className="p-1.5 hover:bg-slate-600 rounded text-slate-300" title="Rotate">
                    <RotateCcw size={14} />
                  </button>
                  <button onClick={() => onRemove(m.id)} className="p-1.5 hover:bg-red-900/50 rounded text-red-400" title="Remove">
                    <Trash2 size={14} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* STATS */}
        {monitors.length > 0 && (
          <div className="bg-slate-900 p-3 rounded border border-slate-700 space-y-2 text-sm">
            <div className="flex justify-between">
              <span className="text-slate-400">Total Width:</span>
              <span>{formatDim(stats.width)}</span>
            </div>
            <div className="flex justify-between">
              <span className="text-slate-400">Total Area:</span>
              <span>{Math.round(stats.area)} sq in</span>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-900 border-t border-slate-700 text-xs text-slate-500 text-center">
        Drag to move • Snap enabled
      </div>
    </div>
  );
};

/**
 * --- COMPONENT: CANVAS TOOLBAR ---
 * Floating zoom controls.
 */
const CanvasToolbar = ({ zoom, setZoom }) => (
  <div className="absolute top-4 right-4 flex gap-2 bg-slate-800/90 backdrop-blur p-2 rounded-lg border border-slate-700 shadow-xl z-30" onMouseDown={e => e.stopPropagation()}>
    <button onClick={() => setZoom(z => Math.max(0.2, z - 0.1))} className="p-2 hover:bg-slate-700 rounded text-slate-200">
      <ZoomOut size={18} />
    </button>
    <div className="px-2 flex items-center text-xs font-mono w-12 justify-center">
      {Math.round(zoom * 100)}%
    </div>
    <button onClick={() => setZoom(z => Math.min(3, z + 0.1))} className="p-2 hover:bg-slate-700 rounded text-slate-200">
      <ZoomIn size={18} />
    </button>
  </div>
);

/**
 * --- MAIN COMPONENT: APP CONTAINER ---
 */
export default function MultiViewPlanner() {
  // App State
  const [monitors, setMonitors] = useState([
    { id: '1', diagonal: 27, ratio: { w: 16, h: 9, label: '16:9 (Standard)' }, orientation: 'landscape', x: 0, y: 0, color: COLORS[0] },
    { id: '2', diagonal: 24, ratio: { w: 16, h: 9, label: '16:9 (Standard)' }, orientation: 'portrait', x: -28 * PPI_SCALE, y: 0, color: COLORS[1] }
  ]);
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [dragState, setDragState] = useState(null);
  const containerRef = useRef(null);

  // --- ACTIONS ---
  const addMonitor = (diagonal, ratio) => {
    setMonitors(prev => [
      ...prev,
      {
        id: Date.now().toString(),
        diagonal: parseFloat(diagonal),
        ratio,
        orientation: 'landscape',
        x: 50, y: 50,
        color: COLORS[prev.length % COLORS.length]
      }
    ]);
  };

  const removeMonitor = (id) => setMonitors(prev => prev.filter(m => m.id !== id));

  const rotateMonitor = (id) => {
    setMonitors(prev => prev.map(m => 
      m.id === id ? { ...m, orientation: m.orientation === 'landscape' ? 'portrait' : 'landscape' } : m
    ));
  };

  // --- DRAG HANDLERS ---
  const handleMouseDown = (e, type, id = null) => {
    e.preventDefault();
    const targetM = type === 'monitor' ? monitors.find(m => m.id === id) : null;
    setDragState({
      type, id,
      startX: e.clientX,
      startY: e.clientY,
      initialX: type === 'monitor' ? targetM.x : pan.x,
      initialY: type === 'monitor' ? targetM.y : pan.y
    });
  };

  useEffect(() => {
    if (!dragState) return;

    const handleMouseMove = (e) => {
      const dx = (e.clientX - dragState.startX) / (dragState.type === 'monitor' ? zoom : 1);
      const dy = (e.clientY - dragState.startY) / (dragState.type === 'monitor' ? zoom : 1);

      if (dragState.type === 'monitor') {
        let newX = dragState.initialX + dx;
        let newY = dragState.initialY + dy;

        // --- SNAPPING LOGIC ---
        const SNAP_THRESHOLD = 15 / zoom;
        let snappedX = false, snappedY = false;

        const currentM = monitors.find(m => m.id === dragState.id);
        let { width: wIn, height: hIn } = calculateDimensions(currentM.diagonal, currentM.ratio.w, currentM.ratio.h);
        if (currentM.orientation === 'portrait') [wIn, hIn] = [hIn, wIn];
        const curW = wIn * PPI_SCALE;
        const curH = hIn * PPI_SCALE;

        monitors.forEach(other => {
          if (other.id === dragState.id) return;

          let { width: owIn, height: ohIn } = calculateDimensions(other.diagonal, other.ratio.w, other.ratio.h);
          if (other.orientation === 'portrait') [owIn, ohIn] = [ohIn, owIn];

          const otherL = other.x, otherR = other.x + (owIn * PPI_SCALE);
          const otherT = other.y, otherB = other.y + (ohIn * PPI_SCALE);

          // X Axis
          if (!snappedX) {
             if (Math.abs(newX - otherR) < SNAP_THRESHOLD) { newX = otherR; snappedX = true; }
             else if (Math.abs((newX + curW) - otherL) < SNAP_THRESHOLD) { newX = otherL - curW; snappedX = true; }
             else if (Math.abs(newX - otherL) < SNAP_THRESHOLD) { newX = otherL; snappedX = true; }
             else if (Math.abs((newX + curW) - otherR) < SNAP_THRESHOLD) { newX = otherR - curW; snappedX = true; }
          }
          // Y Axis
          if (!snappedY) {
             if (Math.abs(newY - otherB) < SNAP_THRESHOLD) { newY = otherB; snappedY = true; }
             else if (Math.abs((newY + curH) - otherT) < SNAP_THRESHOLD) { newY = otherT - curH; snappedY = true; }
             else if (Math.abs(newY - otherT) < SNAP_THRESHOLD) { newY = otherT; snappedY = true; }
             else if (Math.abs((newY + curH) - otherB) < SNAP_THRESHOLD) { newY = otherB - curH; snappedY = true; }
          }
        });

        setMonitors(prev => prev.map(m => m.id === dragState.id ? { ...m, x: newX, y: newY } : m));
      } else {
        setPan({ x: dragState.initialX + (e.clientX - dragState.startX), y: dragState.initialY + (e.clientY - dragState.startY) });
      }
    };

    const handleMouseUp = () => setDragState(null);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragState, monitors, zoom, pan]);

  // --- STATS CALC ---
  const stats = useMemo(() => {
    let totalArea = 0, minX = Infinity, maxX = -Infinity;
    monitors.forEach(m => {
      const { width, height } = calculateDimensions(m.diagonal, m.ratio.w, m.ratio.h);
      totalArea += width * height;
      const wPx = (m.orientation === 'landscape' ? width : height) * PPI_SCALE;
      minX = Math.min(minX, m.x);
      maxX = Math.max(maxX, m.x + wPx);
    });
    return minX === Infinity ? { area: 0, width: 0 } : { area: totalArea, width: (maxX - minX) / PPI_SCALE };
  }, [monitors]);

  return (
    <div className="flex h-screen w-full bg-slate-900 text-slate-100 overflow-hidden font-sans">
      <Sidebar 
        monitors={monitors} 
        onAdd={addMonitor} 
        onRemove={removeMonitor} 
        onRotate={rotateMonitor} 
        stats={stats} 
      />

      <div 
        ref={containerRef}
        className="flex-1 relative overflow-hidden bg-slate-950 cursor-grab active:cursor-grabbing"
        onMouseDown={(e) => handleMouseDown(e, 'pan')}
        style={{ 
          backgroundImage: 'radial-gradient(circle, #334155 1px, transparent 1px)', 
          backgroundSize: `${20 * zoom}px ${20 * zoom}px`,
          backgroundPosition: `${pan.x}px ${pan.y}px`
        }}
      >
        <CanvasToolbar zoom={zoom} setZoom={setZoom} />

        <div 
          className="absolute origin-top-left transition-transform duration-75"
          style={{ transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})` }}
        >
          {/* Origin Marker */}
          <div className="absolute top-0 left-0 w-4 h-4 -translate-x-1/2 -translate-y-1/2 border-l border-t border-slate-600/50"></div>

          {monitors.map(m => (
            <MonitorItem 
              key={m.id} 
              monitor={m} 
              zoom={zoom} 
              isDragging={dragState?.id === m.id} 
              onMouseDown={(e, id) => handleMouseDown(e, 'monitor', id)} 
            />
          ))}
        </div>

        {monitors.length === 0 && (
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <div className="text-center text-slate-600">
              <MousePointer2 className="mx-auto mb-2 opacity-50" size={48} />
              <p className="text-lg">Canvas is empty</p>
              <p className="text-sm">Use the sidebar to add a display</p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

