{
  "name": "MultiView Planner",
  "description": "A visual tool for planning multi-monitor setups. Compare screen sizes, aspect ratios, and orientations on an infinite canvas with snap-to-grid functionality."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface AspectRatio {
  label: string;
  w: number;
  h: number;
}

export interface Monitor {
  id: string;
  diagonal: number;
  ratio: AspectRatio;
  orientation: 'landscape' | 'portrait';
  x: number;
  y: number;
  color: string;
}

export interface DragState {
  type: 'monitor' | 'pan';
  id: string | null;
  startX: number;
  startY: number;
  initialX: number;
  initialY: number;
}

export interface CanvasStats {
  area: number;
  width: number;
}

import { AspectRatio } from './types';

export const PPI_SCALE = 15;

export const COLORS = [
  'bg-blue-500', 
  'bg-emerald-500', 
  'bg-violet-500', 
  'bg-rose-500', 
  'bg-amber-500', 
  'bg-cyan-500', 
  'bg-fuchsia-500', 
  'bg-indigo-500'
];

export const ASPECT_RATIOS: AspectRatio[] = [
  { label: '16:9 (Standard)', w: 16, h: 9 },
  { label: '21:9 (Ultrawide)', w: 21, h: 9 },
  { label: '32:9 (Super Ultrawide)', w: 32, h: 9 },
  { label: '16:10 (Productivity)', w: 16, h: 10 },
  { label: '4:3 (Retro/iPad)', w: 4, h: 3 },
  { label: '1:1 (Square)', w: 1, h: 1 },
];

export const calculateDimensions = (diagonal: number, ratioW: number, ratioH: number) => {
  const angle = Math.atan(ratioH / ratioW);
  const width = diagonal * Math.cos(angle);
  const height = diagonal * Math.sin(angle);
  return { width, height };
};

export const formatDim = (inches: number): string => {
  const cm = inches * 2.54;
  return `${Math.round(cm * 10) / 10} cm (${Math.round(inches * 10) / 10}")`;
};

import React from 'react';
import { Monitor } from '../types';
