      >
        {/* Screen Content */}
        <div className={`w-[calc(100%-8px)] h-[calc(100%-8px)] ${monitor.color} opacity-20 absolute inset-0 m-auto`}></div>
        <div className={`w-[calc(100%-8px)] h-[calc(100%-8px)] absolute inset-0 m-auto flex flex-col items-center justify-center p-2 text-center pointer-events-none`}>
          <span className="text-3xl font-bold text-white/90 drop-shadow-md leading-none select-none">{monitor.diagonal}"</span>
          <span className="text-xs text-white/80 drop-shadow-md font-mono mt-1 select-none">{monitor.ratio.label}</span>
        </div>

        {/* Hover Overlay */}
        <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center text-xs text-white pointer-events-none p-2 text-center">
          <div className="grid grid-cols-2 gap-x-4 gap-y-1 text-left">
            <span className="text-slate-400">Width:</span> <span>{formatDim(widthIn)}</span>
            <span className="text-slate-400">Height:</span> <span>{formatDim(heightIn)}</span>
            <span className="text-slate-400">Area:</span> <span>{Math.round(widthIn * heightIn)} sq in</span>
          </div>
        </div>
      </div>

      {/* External Dimensions (Engineering lines) */}
      <div className="absolute -top-6 left-0 w-full text-center text-[10px] text-slate-400 font-mono opacity-50 group-hover:opacity-100 select-none">
        {formatDim(widthIn)}
      </div>
      <div className="absolute top-0 -left-6 h-full flex items-center text-[10px] text-slate-400 font-mono opacity-50 group-hover:opacity-100 [writing-mode:vertical-lr] rotate-180 select-none">
        {formatDim(heightIn)}
      </div>
    </div>
  );
};

export default MonitorItem;

import React, { useState } from 'react';
import { Plus, Trash2, Monitor as MonitorIcon, RotateCcw } from 'lucide-react';
import { Monitor, AspectRatio, CanvasStats } from '../types';
import { ASPECT_RATIOS } from '../constants';
import { formatDim } from '../utils';

interface SidebarProps {
  monitors: Monitor[];
  onAdd: (diagonal: number, ratio: AspectRatio) => void;
  onRemove: (id: string) => void;
  onRotate: (id: string) => void;
  stats: CanvasStats;
}

const Sidebar: React.FC<SidebarProps> = ({ monitors, onAdd, onRemove, onRotate, stats }) => {
  const [newDiag, setNewDiag] = useState<string>("27");
  const [ratioIdx, setRatioIdx] = useState<number>(0);
  const [customRatio, setCustomRatio] = useState<{ w: string, h: string }>({ w: "16", h: "9" });

  const handleAddClick = () => {
    let finalRatio: AspectRatio;
    if (ratioIdx === -1) {
      finalRatio = {
        w: parseFloat(customRatio.w) || 16,
        h: parseFloat(customRatio.h) || 9,
        label: `${customRatio.w}:${customRatio.h}`
      };
    } else {
      finalRatio = ASPECT_RATIOS[ratioIdx];
    }

    const diag = parseFloat(newDiag);
    if (!isNaN(diag) && diag > 0) {
        onAdd(diag, finalRatio);
    }
  };

  return (
    <div className="w-80 flex-shrink-0 bg-slate-800 border-r border-slate-700 flex flex-col shadow-xl z-20 h-full">
      <div className="p-4 border-b border-slate-700">
        <h1 className="text-xl font-bold flex items-center gap-2 text-blue-400 select-none">
          <MonitorIcon size={24} />
          MultiView Planner
        </h1>
        <p className="text-xs text-slate-400 mt-1">Compare screen sizes & plan layouts.</p>
      </div>

      <div className="p-4 space-y-4 overflow-y-auto flex-1 custom-scrollbar">
        {/* ADD FORM */}
        <div className="bg-slate-700/50 p-4 rounded-lg space-y-3 border border-slate-600">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-300">Add Display</h2>

          <div>
            <label className="block text-xs text-slate-400 mb-1">Diagonal Size (inches)</label>
            <div className="flex items-center gap-2">
              <input 
                type="number" 
                value={newDiag} 
                onChange={(e) => setNewDiag(e.target.value)}
                className="w-full bg-slate-900 border border-slate-600 rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none text-slate-100"
                min="5" max="100"
              />
              <span className="text-sm text-slate-400">"</span>
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-400 mb-1">Aspect Ratio</label>
            <select 
              value={ratioIdx}
              onChange={(e) => setRatioIdx(parseInt(e.target.value))}
              className="w-full bg-slate-900 border border-slate-600 rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none text-slate-100"
            >
              {ASPECT_RATIOS.map((r, idx) => (
                <option key={idx} value={idx}>{r.label}</option>
              ))}
              <option value={-1}>Custom...</option>
            </select>
          </div>

          {ratioIdx === -1 && (
            <div className="grid grid-cols-2 gap-2 animate-in fade-in slide-in-from-top-2 duration-200">
              <div>
                <label className="block text-xs text-slate-400 mb-1">Width Ratio</label>
                <input 
                  type="number"
                  value={customRatio.w}
                  onChange={(e) => setCustomRatio(p => ({ ...p, w: e.target.value }))}
                  className="w-full bg-slate-900 border border-slate-600 rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none text-slate-100"
                  placeholder="16"
                />
              </div>
              <div>
                <label className="block text-xs text-slate-400 mb-1">Height Ratio</label>
                <input 
                  type="number"
                  value={customRatio.h}
                  onChange={(e) => setCustomRatio(p => ({ ...p, h: e.target.value }))}
                  className="w-full bg-slate-900 border border-slate-600 rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none text-slate-100"
                  placeholder="9"
                />
              </div>
            </div>
          )}

          <button 
            onClick={handleAddClick}
            className="w-full bg-blue-600 hover:bg-blue-500 text-white py-2 rounded-md flex items-center justify-center gap-2 text-sm font-medium transition-colors"
          >
            <Plus size={16} /> Add Display
          </button>
        </div>

        {/* LIST */}
        <div className="space-y-2">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-300">Current Setup</h2>
          {monitors.length === 0 && <p className="text-sm text-slate-500 italic">No displays added.</p>}

          <div className="space-y-2 max-h-[300px] overflow-y-auto pr-1 custom-scrollbar">
            {monitors.map((m) => (
              <div key={m.id} className="bg-slate-700 p-3 rounded flex items-center justify-between group border border-transparent hover:border-slate-500 transition-colors">
                <div className="flex items-center gap-3">
                  <div className={`w-3 h-3 rounded-full ${m.color}`}></div>
                  <div>
                    <div className="text-sm font-medium text-slate-200">{m.diagonal}" {m.ratio.label}</div>
                    <div className="text-xs text-slate-400 capitalize">{m.orientation}</div>
                  </div>
                </div>
                <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => onRotate(m.id)} className="p-1.5 hover:bg-slate-600 rounded text-slate-300 transition-colors" title="Rotate">
                    <RotateCcw size={14} />
                  </button>
                  <button onClick={() => onRemove(m.id)} className="p-1.5 hover:bg-red-900/50 rounded text-red-400 transition-colors" title="Remove">
                    <Trash2 size={14} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

