            <div className="flex justify-between">
              <span className="text-slate-400">Total Area:</span>
              <span className="text-slate-200">{Math.round(stats.area)} sq in</span>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-900 border-t border-slate-700 text-xs text-slate-500 text-center select-none">
        Drag to move • Snap enabled
