export default Sidebar;

import React from 'react';
import { ZoomIn, ZoomOut } from 'lucide-react';

interface CanvasToolbarProps {
  zoom: number;
  setZoom: React.Dispatch<React.SetStateAction<number>>;
}

const CanvasToolbar: React.FC<CanvasToolbarProps> = ({ zoom, setZoom }) => (
  <div className="absolute top-4 right-4 flex gap-2 bg-slate-800/90 backdrop-blur p-2 rounded-lg border border-slate-700 shadow-xl z-30" onMouseDown={e => e.stopPropagation()}>
