        {/* STATS */}
        {monitors.length > 0 && (
          <div className={`p-3 rounded border space-y-2 text-sm transition-colors ${isDark ? 'bg-slate-900 border-slate-700' : 'bg-slate-100 border-slate-200'}`}>
