                                <Upload size={14} />
                            </button>
                            <button 
                                onClick={() => handleDeleteLayout(layout.id)}
                                className={`p-1.5 rounded transition-colors opacity-0 group-hover:opacity-100 ${isDark ? 'hover:bg-red-900/30 text-red-400' : 'hover:bg-red-100 text-red-600'}`}
                                title="Delete"
                            >
                                <Trash2 size={14} />
