              step="5"
              value={globalOpacity}
              onChange={(e) => onOpacityChange(parseInt(e.target.value))}
              className="w-full h-1.5 bg-slate-300 rounded-lg appearance-none cursor-pointer accent-blue-600"
              disabled={!transparencyEnabled}
            />
          </div>
        </div>

        {/* LIST - Now Draggable */}
        <div className="space-y-2">
          <div className="flex justify-between items-center">
            <h2 className={`text-sm font-semibold uppercase tracking-wider ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>Displays & Layers</h2>
            <span className={`text-[10px] uppercase font-bold px-1.5 py-0.5 rounded ${isDark ? 'bg-blue-900/30 text-blue-400' : 'bg-blue-100 text-blue-600'}`}>Top Layer at Start</span>
          </div>
          {monitors.length === 0 && <p className={`text-sm italic ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>No displays added.</p>}

          <div className="space-y-2 max-h-[350px] overflow-y-auto pr-1 custom-scrollbar">
            {monitors.map((m, index) => (
              <div 
                key={m.id} 
                draggable
                onDragStart={() => handleDragStart(index)}
                onDragOver={(e) => handleDragOver(e, index)}
                onDragEnd={() => setDraggedIndex(null)}
                className={`p-3 rounded flex flex-col gap-2 border transition-all group ${
                  draggedIndex === index ? 'opacity-40 scale-95' : 'opacity-100'
                } ${isDark ? 'bg-slate-700 border-transparent hover:border-slate-500' : 'bg-slate-50 border-slate-200 hover:border-slate-300'} cursor-grab active:cursor-grabbing`}
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <GripVertical size={14} className={`flex-shrink-0 ${isDark ? 'text-slate-500' : 'text-slate-400'}`} />
                    <button 
                      onClick={() => setShowColorPicker(showColorPicker === m.id ? null : m.id)}
                      className={`w-4 h-4 rounded-full ${m.color} ring-2 ring-offset-1 transition-all ${isDark ? 'ring-offset-slate-700 ring-white/20 hover:ring-white/50' : 'ring-offset-slate-50 ring-black/10 hover:ring-black/30'}`}
                      title="Change color"
                    ></button>
                    <div>
                      <div className={`text-sm font-medium transition-colors ${isDark ? 'text-slate-200' : 'text-slate-800'}`}>{m.diagonal}" {m.ratio.label.split(' ')[0]}</div>
                      <div className={`text-[10px] uppercase tracking-wide font-semibold ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>{m.orientation}</div>
                    </div>
                  </div>
                  <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => onRotate(m.id)} className={`p-1.5 rounded transition-colors ${isDark ? 'hover:bg-slate-600 text-slate-300' : 'hover:bg-slate-200 text-slate-600'}`} title="Rotate">
                      <RotateCcw size={14} />
                    </button>
                    <button onClick={() => onRemove(m.id)} className={`p-1.5 rounded transition-colors ${isDark ? 'hover:bg-red-900/50 text-red-400' : 'hover:bg-red-100 text-red-600'}`} title="Remove">
                      <Trash2 size={14} />
                    </button>
                  </div>
                </div>

                {showColorPicker === m.id && (
                  <div className="flex gap-1.5 flex-wrap p-2 rounded bg-black/10 animate-in fade-in zoom-in-95 duration-150">
                    {COLORS.map((c) => (
                      <button 
                        key={c} 
                        onClick={() => { onUpdateColor(m.id, c); setShowColorPicker(null); }}
                        className={`w-5 h-5 rounded-full ${c} ${m.color === c ? 'ring-2 ring-white' : 'hover:scale-110'} transition-all`}
                      />
                    ))}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>

        {/* ADD FORM */}
        <div className={`p-4 rounded-lg space-y-3 border transition-colors ${isDark ? 'bg-slate-700/50 border-slate-600' : 'bg-slate-50 border-slate-200'}`}>
          <h2 className={`text-sm font-semibold uppercase tracking-wider ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>Add Display</h2>

          <div>
            <label className={`block text-xs mb-1 ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>Diagonal Size (inches)</label>
            <div className="flex items-center gap-2">
              <input 
                type="number" 
                value={newDiag} 
                onChange={(e) => setNewDiag(e.target.value)}
                className={`w-full border rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-colors ${isDark ? 'bg-slate-900 border-slate-600 text-slate-100' : 'bg-white border-slate-300 text-slate-900'}`}
                min="5" max="100"
              />
              <span className={`text-sm ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>"</span>
            </div>
          </div>

          <div>
            <label className={`block text-xs mb-1 ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>Aspect Ratio</label>
            <select 
              value={ratioIdx}
              onChange={(e) => setRatioIdx(parseInt(e.target.value))}
              className={`w-full border rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-colors ${isDark ? 'bg-slate-900 border-slate-600 text-slate-100' : 'bg-white border-slate-300 text-slate-900'}`}
            >
              {ASPECT_RATIOS.map((r, idx) => (
                <option key={idx} value={idx}>{r.label}</option>
              ))}
              <option value={-1}>Custom...</option>
            </select>
          </div>

          {ratioIdx === -1 && (
            <div className="grid grid-cols-2 gap-2 animate-in fade-in slide-in-from-top-2 duration-200">
              <div>
                <label className={`block text-xs mb-1 ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>Width Ratio</label>
                <input 
                  type="number"
                  value={customRatio.w}
                  onChange={(e) => setCustomRatio(p => ({ ...p, w: e.target.value }))}
                  className={`w-full border rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-colors ${isDark ? 'bg-slate-900 border-slate-600 text-slate-100' : 'bg-white border-slate-300 text-slate-900'}`}
                  placeholder="16"
                />
              </div>
              <div>
                <label className={`block text-xs mb-1 ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>Height Ratio</label>
                <input 
                  type="number"
                  value={customRatio.h}
                  onChange={(e) => setCustomRatio(p => ({ ...p, h: e.target.value }))}
                  className={`w-full border rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-colors ${isDark ? 'bg-slate-900 border-slate-600 text-slate-100' : 'bg-white border-slate-300 text-slate-900'}`}
                  placeholder="9"
                />
              </div>
            </div>
          )}

          <button 
            onClick={handleAddClick}
            className={`w-full py-2 rounded-md flex items-center justify-center gap-2 text-sm font-medium transition-colors ${isDark ? 'bg-blue-600 hover:bg-blue-500 text-white' : 'bg-blue-600 hover:bg-blue-700 text-white'}`}
          >
            <Plus size={16} /> Add Display
          </button>
        </div>

        {/* SAVED LAYOUTS SECTION */}
        <div className={`space-y-2 pt-2 border-t transition-colors ${isDark ? 'border-slate-700' : 'border-slate-200'}`}>
            <h2 className={`text-sm font-semibold uppercase tracking-wider flex items-center gap-2 ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>
                <FolderOpen size={14} /> Saved Setups
            </h2>

            <div className="flex gap-2">
                <input 
                    type="text" 
                    value={layoutName}
                    onChange={(e) => setLayoutName(e.target.value)}
                    placeholder="Layout name..."
                    className={`flex-1 border rounded px-2 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-colors ${isDark ? 'bg-slate-900 border-slate-600 text-slate-100' : 'bg-white border-slate-300 text-slate-900'}`}
                />
                <button 
                    onClick={handleSaveLayout}
                    disabled={!layoutName.trim()}
                    className="bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-3 rounded flex items-center justify-center transition-colors"
                    title="Save current setup"
                >
                    <Save size={16} />
                </button>
            </div>

            <div className="space-y-2 max-h-[150px] overflow-y-auto pr-1 custom-scrollbar">
                {savedLayouts.length === 0 && <p className={`text-xs italic ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>No saved layouts.</p>}
                {savedLayouts.map((layout) => (
                    <div key={layout.id} className={`p-2 rounded flex items-center justify-between border transition-colors group ${isDark ? 'bg-slate-700/50 border-slate-700 hover:border-slate-500' : 'bg-slate-50 border-slate-200 hover:border-slate-300'}`}>
                        <div className="overflow-hidden">
                            <div className={`text-sm font-medium truncate ${isDark ? 'text-slate-200' : 'text-slate-800'}`}>{layout.name}</div>
                            <div className={`text-[10px] ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>{layout.monitors.length} displays • {new Date(layout.timestamp).toLocaleDateString()}</div>
                        </div>
                        <div className="flex items-center gap-1">
                            <button 
                                onClick={() => onLoadLayout(layout.monitors)}
                                className={`p-1.5 rounded transition-colors ${isDark ? 'hover:bg-blue-600/20 text-blue-400' : 'hover:bg-blue-100 text-blue-600'}`}
                                title="Load this setup"
                            >
                                <Upload size={14} />
                            </button>
                            <button 
                                onClick={() => handleDeleteLayout(layout.id)}
                                className={`p-1.5 rounded transition-colors opacity-0 group-hover:opacity-100 ${isDark ? 'hover:bg-red-900/30 text-red-400' : 'hover:bg-red-100 text-red-600'}`}
                                title="Delete"
                            >
                                <Trash2 size={14} />
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>

        {/* STATS */}
        {monitors.length > 0 && (
          <div className={`p-3 rounded border space-y-2 text-sm transition-colors ${isDark ? 'bg-slate-900 border-slate-700' : 'bg-slate-100 border-slate-200'}`}>
            <div className="flex justify-between">
              <span className={isDark ? 'text-slate-400' : 'text-slate-500'}>Total Width:</span>
              <span className={isDark ? 'text-slate-200' : 'text-slate-800'}>{formatDim(stats.width)}</span>
            </div>
            <div className="flex justify-between">
              <span className={isDark ? 'text-slate-400' : 'text-slate-500'}>Total Area:</span>
              <span className={isDark ? 'text-slate-200' : 'text-slate-800'}>{Math.round(stats.area)} sq in</span>
            </div>
          </div>
        )}
      </div>

      <div className={`p-4 border-t text-xs text-center select-none transition-colors ${isDark ? 'bg-slate-900 border-slate-700 text-slate-500' : 'bg-slate-50 border-slate-200 text-slate-400'}`}>
        Drag to move • Snap enabled
      </div>
    </div>
  );
};

export default Sidebar;

import React from 'react';
import { Monitor } from '../types';
import { calculateDimensions, formatDim } from '../utils';
import { PPI_SCALE } from '../constants';

interface MonitorItemProps {
  monitor: Monitor;
  zoom: number;
  isDragging: boolean;
  onMouseDown: (e: React.MouseEvent, id: string) => void;
  theme: 'dark' | 'light';
  transparencyEnabled: boolean;
  globalOpacity: number;
  zIndex?: number;
}

const MonitorItem: React.FC<MonitorItemProps> = ({ 
  monitor, isDragging, onMouseDown, theme, transparencyEnabled, globalOpacity, zIndex
}) => {
  const { width, height } = calculateDimensions(monitor.diagonal, monitor.ratio.w, monitor.ratio.h);

  // Swap dimensions if portrait
  const widthIn = monitor.orientation === 'landscape' ? width : height;
  const heightIn = monitor.orientation === 'landscape' ? height : width;

  const widthPx = widthIn * PPI_SCALE;
  const heightPx = heightIn * PPI_SCALE;

  const isDark = theme === 'dark';

  // Opacity logic: Apply to the entire monitor body for stacking effect
  const opacityValue = transparencyEnabled ? globalOpacity / 100 : 1;

  return (
    <div
      onMouseDown={(e) => { e.stopPropagation(); onMouseDown(e, monitor.id); }}
      className="absolute group transition-shadow duration-200"
      style={{
        transform: `translate(${monitor.x}px, ${monitor.y}px)`,
        width: widthPx,
        height: heightPx,
        cursor: 'move',
        zIndex: isDragging ? 999 : (zIndex || 10)
      }}
    >
      {/* Monitor Body (Bezel + Screen) */}
      <div 
        className={`w-full h-full rounded-sm border-2 shadow-2xl flex flex-col items-center justify-center relative overflow-hidden transition-all duration-300 ${
          isDark 
            ? 'bg-slate-800 border-slate-600' 
            : 'bg-slate-900 border-slate-700'
        } ${isDragging ? 'shadow-blue-500/40 ring-2 ring-blue-500' : ''}`}
        style={{ opacity: opacityValue }}
      >
        {/* Screen Color Layer */}
        <div 
          className={`w-[calc(100%-8px)] h-[calc(100%-8px)] ${monitor.color} absolute inset-0 m-auto brightness-110 saturate-125`}
        ></div>

        {/* Label Content */}
        <div className="w-full h-full absolute inset-0 flex flex-col items-center justify-center p-2 text-center pointer-events-none z-10">
          <span className="text-3xl font-black text-white drop-shadow-[0_2px_4px_rgba(0,0,0,0.8)] leading-none select-none">
            {monitor.diagonal}"
          </span>
          <span className="text-[10px] text-white font-bold drop-shadow-md font-mono mt-1 select-none uppercase tracking-widest bg-black/20 px-1 rounded">
            {monitor.ratio.label.split(' ')[0]}
          </span>
        </div>

        {/* Hover Information Layer - Stays opaque on hover relative to the body */}
        <div className="absolute inset-0 bg-black/80 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center text-xs text-white pointer-events-none p-2 text-center z-20">
          <div className="grid grid-cols-2 gap-x-4 gap-y-1 text-left font-medium">
            <span className="text-slate-400">Width:</span> <span>{formatDim(widthIn)}</span>
            <span className="text-slate-400">Height:</span> <span>{formatDim(heightIn)}</span>
            <span className="text-slate-400">Area:</span> <span>{Math.round(widthIn * heightIn)} in²</span>
          </div>
        </div>
      </div>

      {/* External Dimensions (Engineering lines) */}
      <div className={`absolute -top-6 left-0 w-full text-center text-[10px] font-mono font-bold opacity-60 group-hover:opacity-100 select-none transition-colors ${isDark ? 'text-slate-400' : 'text-slate-600'}`}>
        {formatDim(widthIn)}
      </div>
      <div className={`absolute top-0 -left-6 h-full flex items-center text-[10px] font-mono font-bold opacity-60 group-hover:opacity-100 [writing-mode:vertical-lr] rotate-180 select-none transition-colors ${isDark ? 'text-slate-400' : 'text-slate-600'}`}>
        {formatDim(heightIn)}
      </div>
    </div>
  );
};

export default MonitorItem;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { MousePointer2 } from 'lucide-react';
import MonitorItem from './components/MonitorItem';
import Sidebar from './components/Sidebar';
import CanvasToolbar from './components/CanvasToolbar';
import { Monitor, DragState, AspectRatio, CanvasStats } from './types';
import { COLORS, PPI_SCALE } from './constants';
import { calculateDimensions } from './utils';

export default function App() {
  const [monitors, setMonitors] = useState<Monitor[]>([
    { id: '1', diagonal: 27, ratio: { w: 16, h: 9, label: '16:9 (Standard)' }, orientation: 'landscape', x: 0, y: 0, color: COLORS[0] },
    { id: '2', diagonal: 24, ratio: { w: 16, h: 9, label: '16:9 (Standard)' }, orientation: 'portrait', x: 30 * PPI_SCALE, y: 0, color: COLORS[1] }
  ]);
  const [zoom, setZoom] = useState<number>(1);
  const [pan, setPan] = useState<{ x: number, y: number }>({ x: 100, y: 100 });
  const [dragState, setDragState] = useState<DragState | null>(null);
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');

  // Transparency Settings
  const [transparencyEnabled, setTransparencyEnabled] = useState<boolean>(true);
  const [globalOpacity, setGlobalOpacity] = useState<number>(65); // Changed default from 30 to 65

  const containerRef = useRef<HTMLDivElement>(null);

  // --- ACTIONS ---
  const addMonitor = (diagonal: number, ratio: AspectRatio) => {
    setMonitors(prev => [
      {
        id: Date.now().toString(),
        diagonal: diagonal,
        ratio,
        orientation: 'landscape',
        x: 50, y: 50,
        color: COLORS[prev.length % COLORS.length]
      },
      ...prev,
    ]);
  };

  const removeMonitor = (id: string) => setMonitors(prev => prev.filter(m => m.id !== id));

  const rotateMonitor = (id: string) => {
    setMonitors(prev => prev.map(m => 
      m.id === id ? { ...m, orientation: m.orientation === 'landscape' ? 'portrait' : 'landscape' } : m
    ));
  };

  const updateMonitorColor = (id: string, color: string) => {
    setMonitors(prev => prev.map(m => m.id === id ? { ...m, color } : m));
  };

  const reorderMonitors = (sourceIndex: number, destIndex: number) => {
    setMonitors(prev => {
      const result = Array.from(prev);
      const [removed] = result.splice(sourceIndex, 1);
      result.splice(destIndex, 0, removed);
      return result;
    });
  };

  const loadLayout = (loadedMonitors: Monitor[]) => {
    setMonitors(loadedMonitors);
  };

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // --- DRAG HANDLERS ---
  const handleMouseDown = (e: React.MouseEvent, type: 'monitor' | 'pan', id: string | null = null) => {
    e.preventDefault();
    const targetM = type === 'monitor' ? monitors.find(m => m.id === id) : null;
    setDragState({
      type, id,
      startX: e.clientX,
      startY: e.clientY,
      initialX: type === 'monitor' && targetM ? targetM.x : pan.x,
      initialY: type === 'monitor' && targetM ? targetM.y : pan.y
    });
  };

  useEffect(() => {
    if (!dragState) return;

    const handleMouseMove = (e: MouseEvent) => {
      const dx = (e.clientX - dragState.startX) / (dragState.type === 'monitor' ? zoom : 1);
      const dy = (e.clientY - dragState.startY) / (dragState.type === 'monitor' ? zoom : 1);

      if (dragState.type === 'monitor' && dragState.id) {
        let newX = dragState.initialX + dx;
        let newY = dragState.initialY + dy;

        const SNAP_THRESHOLD = 15 / zoom;
        let snappedX = false;
        let snappedY = false;

        const currentM = monitors.find(m => m.id === dragState.id);
        if (currentM) {
          let { width: wIn, height: hIn } = calculateDimensions(currentM.diagonal, currentM.ratio.w, currentM.ratio.h);
          if (currentM.orientation === 'portrait') [wIn, hIn] = [hIn, wIn];
          const curW = wIn * PPI_SCALE;
          const curH = hIn * PPI_SCALE;

          monitors.forEach(other => {
            if (other.id === dragState.id) return;
            let { width: owIn, height: ohIn } = calculateDimensions(other.diagonal, other.ratio.w, other.ratio.h);
            if (other.orientation === 'portrait') [owIn, ohIn] = [ohIn, owIn];
            const otherL = other.x, otherR = other.x + (owIn * PPI_SCALE);
            const otherT = other.y, otherB = other.y + (ohIn * PPI_SCALE);

            if (!snappedX) {
              if (Math.abs(newX - otherR) < SNAP_THRESHOLD) { newX = otherR; snappedX = true; }
              else if (Math.abs((newX + curW) - otherL) < SNAP_THRESHOLD) { newX = otherL - curW; snappedX = true; }
              else if (Math.abs(newX - otherL) < SNAP_THRESHOLD) { newX = otherL; snappedX = true; }
              else if (Math.abs((newX + curW) - otherR) < SNAP_THRESHOLD) { newX = otherR - curW; snappedX = true; }
            }
            if (!snappedY) {
              if (Math.abs(newY - otherB) < SNAP_THRESHOLD) { newY = otherB; snappedY = true; }
              else if (Math.abs((newY + curH) - otherT) < SNAP_THRESHOLD) { newY = otherT - curH; snappedY = true; }
              else if (Math.abs(newY - otherT) < SNAP_THRESHOLD) { newY = otherT; snappedY = true; }
              else if (Math.abs((newY + curH) - otherB) < SNAP_THRESHOLD) { newY = otherB - curH; snappedY = true; }
            }
          });
        }
        setMonitors(prev => prev.map(m => m.id === dragState.id ? { ...m, x: newX, y: newY } : m));
      } else {
        setPan({ x: dragState.initialX + (e.clientX - dragState.startX), y: dragState.initialY + (e.clientY - dragState.startY) });
      }
    };

    const handleMouseUp = () => setDragState(null);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragState, monitors, zoom, pan]);

  const stats: CanvasStats = useMemo(() => {
    let totalArea = 0, minX = Infinity, maxX = -Infinity;
    monitors.forEach(m => {
      const { width, height } = calculateDimensions(m.diagonal, m.ratio.w, m.ratio.h);
      totalArea += width * height;
      const wPx = (m.orientation === 'landscape' ? width : height) * PPI_SCALE;
      minX = Math.min(minX, m.x);
      maxX = Math.max(maxX, m.x + wPx);
    });
    return minX === Infinity ? { area: 0, width: 0 } : { area: totalArea, width: (maxX - minX) / PPI_SCALE };
  }, [monitors]);

  const isDark = theme === 'dark';

  return (
    <div className={`flex h-screen w-full transition-colors duration-300 ${isDark ? 'bg-slate-900 text-slate-100' : 'bg-slate-50 text-slate-900'} overflow-hidden font-sans`}>
      <Sidebar 
        monitors={monitors} 
        onAdd={addMonitor} 
        onRemove={removeMonitor} 
        onRotate={rotateMonitor}
        onUpdateColor={updateMonitorColor}
        onLoadLayout={loadLayout}
        onReorder={reorderMonitors}
        stats={stats}
        theme={theme}
        onToggleTheme={toggleTheme}
        transparencyEnabled={transparencyEnabled}
        onToggleTransparency={() => setTransparencyEnabled(!transparencyEnabled)}
        globalOpacity={globalOpacity}
        onOpacityChange={setGlobalOpacity}
      />

      <div 
        ref={containerRef}
        className={`flex-1 relative overflow-hidden cursor-grab active:cursor-grabbing ${isDark ? 'bg-slate-950' : 'bg-slate-100'}`}
        onMouseDown={(e) => handleMouseDown(e, 'pan')}
        style={{ 
          backgroundImage: `radial-gradient(circle, ${isDark ? '#334155' : '#cbd5e1'} 1px, transparent 1px)`, 
          backgroundSize: `${20 * zoom}px ${20 * zoom}px`,
          backgroundPosition: `${pan.x}px ${pan.y}px`
        }}
      >
        <CanvasToolbar zoom={zoom} setZoom={setZoom} theme={theme} />

        <div 
          className="absolute origin-top-left transition-transform duration-75"
          style={{ transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})` }}
        >
          <div className={`absolute top-0 left-0 w-4 h-4 -translate-x-1/2 -translate-y-1/2 border-l border-t ${isDark ? 'border-slate-600/50' : 'border-slate-400'}`}></div>

          {monitors.map((m, index) => (
            <MonitorItem 
              key={m.id} 
              monitor={m} 
              zoom={zoom} 
              isDragging={dragState?.id === m.id} 
              onMouseDown={(e, id) => handleMouseDown(e, 'monitor', id)} 
              theme={theme}
              transparencyEnabled={transparencyEnabled}
              globalOpacity={globalOpacity}
              zIndex={monitors.length - index}
            />
          ))}
